import "./checkbox.css";

import { Check } from "lucide-react";
import { Checkbox } from "radix-ui";
import { cn } from "tailwind-variants";

import { checkboxVariants } from "./checkbox.variants";

export type CheckboxProps = React.ComponentProps<typeof Checkbox.Root>;

export const CheckboxRoot = ({ className, ...props }: CheckboxProps) => {
  const { indicator, root } = checkboxVariants();

  return (
    <Checkbox.Root className={cn(root(), className)} {...props}>
      <Checkbox.Indicator className={indicator()}>
        <Check />
      </Checkbox.Indicator>
    </Checkbox.Root>
  );
};

import { tv, type VariantProps } from "tailwind-variants";

export const checkboxVariants = tv({
  slots: {
    indicator: "checkbox__indicator",
    root: "checkbox",
  },
});

export type CheckboxVariants = VariantProps<typeof checkboxVariants>;

.checkbox {
  @apply border-primary bg-background flex size-4 shrink-0 appearance-none items-center justify-center rounded-sm border transition-colors;

  &:hover {
    @apply bg-accent;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &:disabled {
    @apply cursor-not-allowed opacity-50;
  }

  &[data-state="checked"] {
    @apply bg-primary text-primary-foreground;
  }
}

.checkbox__indicator {
  @apply flex items-center justify-center text-current;

  & svg {
    @apply size-3.5;
  }
}

import { CheckboxRoot } from "./checkbox";

export const Checkbox = {
  Root: CheckboxRoot,
};

export { CheckboxRoot };

export type { CheckboxProps } from "./checkbox";

export { type CheckboxVariants, checkboxVariants } from "./checkbox.variants";
